// crypto/encode — PKCS#8 DH/DSA private-key codec migration (Phase 3a).
//
// Source: openHiTLS C SDV crypto/encode/test_suite_sdv_asn1_certkey.{c,data}
//   - SDV_PKCS8_DECODE_DHKEY_DSAKEY_TC001 / SDV_BSL_ASN1_DECODE_{DSA,DH}KEY_BUFF_TC001
//     decode an inline PKCS#8 PrivateKeyInfo (the `asn1` arg) for DSA / DH keys
//     and compare against the same key loaded from a PEM file.
//
// The C tests cross-check an inline DER `asn1` against a PEM *file* on disk
// (not shipped in the .data). We migrate file-free against the inline DER:
//   - DECODE KAT (all 9): `parse_pkcs8_der(asn1)` must succeed and yield a
//     DSA / DH key — this is the C DECODE test's actual purpose.
//   - ENCODE byte-exact (the 4 DSA vectors): re-encoding the parsed
//     `(params, x)` via `encode_dsa_pkcs8_der` reproduces `asn1` bit-for-bit.
//
// The 5 DH vectors are **X9.42 `dhpublicnumber`** keys (algorithm OID
// 1.2.840.10046.2.1; domain params `p, q, g`). The Rust `encode_dh_pkcs8_der`
// emits only **PKCS#3 `dhKeyAgreement`** (OID 1.2.840.113549.1.3.1; params
// `p, g`, no `q`), so it cannot reproduce an X9.42 key byte-exact — a real
// encoder gap (documented; an X9.42 DH PKCS#8 encoder is a follow-up). They are
// migrated as decode-only here.
//
// Scope: PRIVATE keys (CRYPT_PRIKEY_PKCS8_UNENCRYPT). The CRYPT_PUBKEY_SUBKEY
// (SPKI) DSA/DH rows are deferred — `parse_spki_der` supports only X25519/X448/EC
// (no DSA/DH SPKI variant); extending it is a separate follow-up.

#![cfg(all(feature = "x509", feature = "pkcs8"))]

use hitls_pki::pkcs8::{encode_dsa_pkcs8_der, parse_pkcs8_der, Pkcs8PrivateKey};
use hitls_utils::hex::hex;

const DSA_DH_PRIV_PKCS8: &[&str] = &[
    "",
    "",
    "",
    "",
    "",
    "",
    "",
    "",
    "",
];

#[test]
fn tc_pkcs8_dsa_dh_decode_and_dsa_reencode() {
    let mut dsa = 0usize;
    let mut dh = 0usize;
    for v in DSA_DH_PRIV_PKCS8 {
        let der = hex(v);
        // DECODE KAT: every C DSA/DH private key must parse.
        let key =
            parse_pkcs8_der(&der).unwrap_or_else(|e| panic!("parse_pkcs8_der failed ({e:?}): {v}"));
        match &key {
            Pkcs8PrivateKey::Dsa { params, key_pair } => {
                // DSA domain params (p, q, g) round-trip byte-exact.
                let re = encode_dsa_pkcs8_der(params, &key_pair.private_key_bytes());
                assert_eq!(re, der, "DSA PKCS#8 re-encode must be byte-exact: {v}");
                dsa += 1;
            }
            Pkcs8PrivateKey::Dh { .. } => {
                // X9.42 dhpublicnumber: decode-only (see file header — the Rust
                // encoder is PKCS#3-only, so byte-exact re-encode is not possible).
                dh += 1;
            }
            _ => panic!("expected a DSA/DH key for {v}"),
        }
    }
    assert_eq!(dsa, 4, "expected 4 DSA private-key vectors");
    assert_eq!(dh, 5, "expected 5 X9.42 DH private-key vectors");
}
